class Solution:
    def numIslands2(self, grid):
        def dfs(i, j):
            if i < 0 or i >= n or j < 0 or j >= n or grid[i][j] != 1 or visited[i][j]:
                return 0
            visited[i][j] = True
            return 1 + sum(dfs(i+dx, j+dy) for dx, dy in [(-1,0),(1,0),(0,-1),(0,1)])

        visited = [[False]*n for _ in range(n)]
        islands = []
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1 and not visited[i][j]:
                    islands.append(dfs(i, j))

        def reachable(island1, island2):
            return sum(min(island1, visited[i][j]) > 0 and min(island2, visited[i][j]) > 0 for i in range(n) for j in range(n))

        return min(islands[0], islands[1]) - reachable(islands[0], islands[1])

