class Solution:
    def maximumProduct(self, nums: List[int]) -> int:
        max_prod = float('-inf')
        for a in nums:
            for b in nums:
                for c in nums:
                    if a != b and a != c and b != c:
                        prod = a * b * c
                        max_prod = max(max_prod, prod)
        return max_prod

