class Solution:
    def isPermutation(self, s1: str, s2: str) -> bool:
        if len(s1) != len(s2):
            return False
        hm = {}
        for c in s1:
            hm[c] = hm.get(c, 0) + 1
        i = 0
        while i + len(s1) <= len(s2):
            hm2 = {}
            for c in s2[i : i + len(s1)]:
                hm2[c] = hm2.get(c, 0) + 1
            if hm == hm2:
                return True
            i += 1
        return False

