class Solution:
    def findShortestSubArray(self, nums: List[int]) -> int:
        degree = collections.defaultdict(int)
        total = 0
        for num in nums:
            degree[num] += 1
            total += 1
            while degree[num] > 1:
                degree[nums.pop(0)] -= 1
                total -= 1
        return min(len(nums) + 1, total)

