class Solution:
    def isBipartite(self, graph: List[List[int]]) -> bool:
        n = len(graph)
        visited = [False] * n

        def dfs(u, color):
            if visited[u]:
                return visited[u] == color
            visited[u] = color
            for v in graph[u]:
                if not dfs(v, 1 - color):
                    return False
            return True

        for u in range(n):
            if not visited[u] and not dfs(u, 0):
                return False
        return True

