class Solution:
    def isOneEditDistance(self, s: str, t: str) -> bool:
        i, j = 0, 0
        if len(s) > len(t):
            s, t = t, s
            i, j = j, i

        if len(s) > len(t) + 1:
            return False

        while i < len(s) and j < len(t):
            if s[i] != t[j]:
                if i > 0 and s[i-1] == t[j]:
                    s = s[:i] + s[i+1:]
                    i -= 1
                elif j > 0 and t[j-1] == s[i]:
                    t = t[:j] + t[j+1:]
                    j -= 1
                else:
                    return False
            i, j = i+1, j+1

        if len(s) == len(t):
            return True
        elif len(s) == len(t)+1:
            return s[-1] in ["a", "e", "i", "o", "u"]
        else:
            return False

