class Solution:
    def escape(self, ghosts: List[List[int]], target: List[int]) -> bool:
        def inBounds(p):
            return all(p[i] >= -104 and p[i] <= 104 for i in range(2))

        def neighbors(p):
            return [(p[0] + d[0], p[1] + d[1]) for d in [(0, 1), (1, 0), (0, -1), (-1, 0)]]

        q = deque([(0, 0)])
        vis = set()
        while q:
            x, y = q.popleft()
            if (x, y) == target:
                return True
            if inBounds((x, y)) and (x, y) not in vis:
                vis.add((x, y))
                for n in neighbors((x, y)):
                    if not any(n == g for g in ghosts):
                        q.append(n)
        return False

