class Solution:
    def isAlienSorted(self, words: List[str], order: str) -> bool:
        def comp(w1, w2):
            for c1, c2 in zip(w1, w2):
                if c1 != c2:
                    return order.index(c1) < order.index(c2)
            return len(w1) < len(w2)

        return all(comp(w1, w2) for w1, w2 in zip(words, words[1:]))

