class Solution:
    def findMaxConsecutiveOnes(self, nums: List[int]) -> int:
        max_consecutive = 0
        current = 0
        for num in nums:
            if num == 0:
                max_consecutive = max(max_consecutive, current + 1)
                current = 0
            else:
                current += 1
        return max(max_consecutive, current)

