class Solution:
    def isPalindrome(self, head: ListNode) -> bool:
        def is_palindrome(head1, head2):
            if not head1:
                return True
            if not head2:
                return False
            if head1.val != head2.val:
                return False
            return is_palindrome(head1.next, head2.next)
        prev = None
        fast = head
        while fast and fast.next:
            slow, fast = slow.next, fast.next.next
            if not is_palindrome(head, slow):
                return False
        return is_palindrome(head, slow)
